[SRSReportParameterAttribute(classStr(ETGRminCocoaContract))]
class ETGRminCocoaDataProvider extends  SRSReportDataProviderPreProcessTempDB

{
    ETGRminCocoaTemp                     ETGRminCocoaTemp;
    TransDate                               _fromDate,_ToDate;
    List                                    _InvoiceId= new List(Types::String);
    List                                    _ItemId= new List(Types::String);
    List                                    _VendAccount= new List(Types::String);
    VendPackingSlipJour                     _VendPackingSlipJour;
    VendPackingSlipTrans                    _VendPackingSlipTrans;
    ETGPurchLineCoCOAQuality                _ETGPurchLineCoCOAQuality;
    PurchLine                               _PurchLine;

}

